// Final visibility and schedule-card enforcement.
(function(){
  function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
  function monday(d){d=new Date(d||new Date());var n=(d.getDay()+6)%7;d.setHours(12,0,0,0);d.setDate(d.getDate()-n);return d}
  function add(d,n){d=new Date(d);d.setDate(d.getDate()+n);return d}
  function iso(d){return d.toISOString().slice(0,10)}
  function label(d,opts){return new Date(d+'T12:00:00').toLocaleDateString('en-GB',opts)}
  function weekKey(date){return iso(monday(new Date(date+'T12:00:00')))}
  function isPublished(s){var wk=state.publishedWeeks&&state.publishedWeeks[weekKey(s.date)];return !!(s.publishedAt || (wk&&Array.isArray(wk.shiftIds)&&wk.shiftIds.includes(s.id)))}
  function visibleShift(s){return isAdmin() || isPublished(s)}
  function isOnShift(s){var l=(state.logs||{})[s.id];return !!(l&&l.in&&!l.out)}
  function uname(id){if(!id||id==='unassigned')return 'Unassigned';var u=(state.users||[]).find(function(x){return x.id===id});return u?(u.nickname||u.name||u.firstName||'User'):'Unassigned'}
  function days(){var base=window.__rbWeekStart?new Date(window.__rbWeekStart+'T12:00:00'):monday(new Date());base=monday(base);window.__rbWeekStart=iso(base);return [0,1,2,3,4,5,6].map(function(n){return iso(add(base,n))})}
  function topShell(inner){var u=me();var set=state.permissionSets[u.permissionSetId]||{name:'Staff'};var nav=['<button class="tab '+(state.view==='home'?'active':'')+'" onclick="setView(\'home\')">Home</button>','<button class="tab '+(state.view==='rota'?'active':'')+'" onclick="setView(\'rota\')">Schedule</button>'];if(can('viewPeople')||can('manageUsers'))nav.push('<button class="tab '+(state.view==='people'?'active':'')+'" onclick="setView(\'people\')">People</button>');if(isAdmin())nav.push('<button class="tab '+(state.view==='admin'?'active':'')+'" onclick="setView(\'admin\')">Admin</button>');document.getElementById('app').innerHTML='<header class="topbar"><div><h1>Rota App</h1><p>'+esc(u.name)+' · '+esc(set.name||'Staff')+'</p></div><div class="topActions"><select id="currentUserSelect">'+state.users.map(function(x){return '<option value="'+x.id+'" '+(x.id===state.currentUserId?'selected':'')+'>'+esc(x.nickname||x.name)+' ('+esc((state.permissionSets[x.permissionSetId]||{}).name||'Staff')+')</option>'}).join('')+'</select></div></header><nav class="tabs">'+nav.join('')+'</nav><main>'+inner+'</main>';document.getElementById('currentUserSelect').onchange=function(e){state.currentUserId=e.target.value;save();render()}}
  function shiftCard(s){var live=isOnShift(s),cls=s.userId==='unassigned'?'unassigned':live?'onShift':isPublished(s)?'published':'planned';var notes=s.notes||'';return '<button type="button" class="scheduleShiftBlock '+cls+'" onclick="openShiftModal(\''+s.id+'\')"><span class="shiftLine shiftUserLine">'+esc(uname(s.userId))+'</span><span class="shiftLine shiftStartLine">'+esc(s.start)+' -</span><span class="shiftLine shiftEndLine">'+esc(s.end)+'</span><span class="shiftLine shiftNotesLine">'+(notes?esc(notes):'&nbsp;')+'</span>'+(live?'<span class="shiftLine shiftStatusLine">On Shift</span>':'')+'</button>'}
  window.renderRota=function(){var ds=days(),first=ds[0],last=ds[6];var range=label(first,{day:'numeric',month:'short',year:'numeric'})+' - '+label(last,{day:'numeric',month:'short',year:'numeric'});var html='<div class="toolbar scheduleToolbarFinal"><button class="secondary" onclick="window.__rbWeekStart=iso(add(new Date(window.__rbWeekStart+\'T12:00:00\'),-7));renderRota()">‹</button><strong>'+range+'</strong><button class="secondary" onclick="window.__rbWeekStart=iso(add(new Date(window.__rbWeekStart+\'T12:00:00\'),7));renderRota()">›</button></div><div id="rotaGrid" class="bandedRota"><div class="bandDayHeader">'+ds.map(function(d){return '<div class="bandDayHead"><strong>'+label(d,{weekday:'short'})+'</strong><span>'+label(d,{day:'numeric',month:'short'})+'</span></div>'}).join('')+'</div>'+(state.sections||[]).map(function(sec){return '<section class="rotaSectionBand"><div class="sectionBandTitle">'+esc(sec)+'</div><div class="bandWeekGrid">'+ds.map(function(d){var shifts=(state.shifts||[]).filter(function(s){return s.section===sec&&s.date===d&&visibleShift(s)}).sort(function(a,b){return String(a.start).localeCompare(String(b.start))});return '<div class="bandDayCell compactDayCell">'+(shifts.length?shifts.map(shiftCard).join(''):'<span class="muted emptyCell">—</span>')+((typeof can!=='function'||can('manageRota'))?'<button class="cellAddShift" onclick="openShiftModal(\'\',\''+d+'\',\''+esc(sec)+'\')">+</button>':'')+'</div>'}).join('')+'</div></section>'}).join('')+'</div>'+(isAdmin()?'<div class="scheduleAdminTools"><h2>Rota planning</h2><div class="planningActions scheduleActions"><button onclick="copyCurrentWeek()">Copy current week</button><button class="secondary" onclick="pasteCopiedWeek()">Paste copied week here</button><button class="secondary" onclick="saveCurrentWeekAsTemplate()">Save week as template</button><button onclick="publishCurrentWeek()">Save rota</button></div></div>':'');topShell(html);window.scrollTo(0,0)};
  try{renderRota=window.renderRota;shell=topShell}catch(e){}
  window.__visibleShift=visibleShift;
  if(state.view==='rota')window.renderRota();
})();
